package chisel3.stage.phases

import chisel3.Module
import chisel3.experimental.hierarchy.core.Definition
import chisel3.experimental.BaseModule
import chisel3.internal.ExceptionHelpers.ThrowableHelpers
import chisel3.internal.{Builder, BuilderContextCache, DynamicContext, ElaborationTrace}
import chisel3.internal.firrtl.ir
import chisel3.stage.{
  ChiselCircuitAnnotation,
  ChiselGeneratorAnnotation,
  ChiselOptions,
  ChiselOptionsView,
  DesignAnnotation,
  ThrowOnFirstErrorAnnotation
}
import firrtl.{annoSeqToSeq, seqToAnnoSeq, AnnotationSeq}
import firrtl.options.{Dependency, Phase}
import firrtl.options.Viewer.view
import logger.{LoggerOptions, LoggerOptionsView}

import scala.collection.mutable
import scala.annotation.nowarn

/** Elaborate all [[chisel3.stage.ChiselGeneratorAnnotation]]s into [[chisel3.stage.ChiselCircuitAnnotation]]s.
  */
class Elaborate extends Phase {

  override def prerequisites: Seq[Dependency[Phase]] = Seq(
    Dependency[chisel3.stage.phases.Checks],
    Dependency(_root_.logger.phases.Checks)
  )
  override def optionalPrerequisites = Seq.empty
  override def optionalPrerequisiteOf = Seq.empty
  override def invalidates(a: Phase) = false

  def transform(annotations: AnnotationSeq): AnnotationSeq = annotations.flatMap {
    case ChiselGeneratorAnnotation(gen) =>
      val chiselOptions = view[ChiselOptions](annotations)
      val loggerOptions = view[LoggerOptions](annotations)
      try {
        val elaborationTrace = new ElaborationTrace
        val context =
          new DynamicContext(
            annotations,
            chiselOptions.throwOnFirstError,
            chiselOptions.useLegacyWidth,
            chiselOptions.includeUtilMetadata,
            chiselOptions.useSRAMBlackbox,
            chiselOptions.warningFilters,
            chiselOptions.sourceRoots,
            None,
            loggerOptions,
            mutable.LinkedHashSet[Definition[_ <: BaseModule]](),
            BuilderContextCache.empty,
            chiselOptions.layerMap,
            chiselOptions.inlineTestIncluder,
            chiselOptions.suppressSourceInfo,
            false,
            elaborationTrace
          )
        val (elaboratedCircuit, dut) = {
          Builder.build(Module(gen()), context)
        }
        elaborationTrace.finish()

        // Extract the Chisel layers from a circuit via an in-order walk.
        def walkLayers(layer: ir.Layer, layers: Seq[chisel3.layer.Layer] = Nil): Seq[chisel3.layer.Layer] = {
          layer.children.foldLeft(layers :+ layer.chiselLayer) { case (acc, x) => walkLayers(x, acc) }
        }

        Seq(
          ChiselCircuitAnnotation(elaboratedCircuit),
          DesignAnnotation(dut, layers = elaboratedCircuit._circuit.layers.flatMap(walkLayers(_)))
        )
      } catch {
        /* if any throwable comes back and we're in "stack trace trimming" mode, then print an error and trim the stack trace
         */
        case scala.util.control.NonFatal(a) =>
          if (!chiselOptions.printFullStackTrace) {
            a.trimStackTraceToUserCode()
          }
          throw (a)
      }
    case a => Some(a)
  }

}

}

def errors: ErrorLog = dynamicContext.errors
def error(m: => String)(implicit sourceInfo: SourceInfo): Unit = {
  // If --throw-on-first-error is requested, throw an exception instead of aggregating errors
  if (dynamicContextVar.value.isDefined) {
    errors.error(m, sourceInfo)
  } else {
    throwException(m)
  }
}
def warning(warning: Warning): Unit =
  if (dynamicContextVar.value.isDefined) errors.warning(warning)

def deprecated(m: => String, location: Option[String] = None): Unit =
  if (dynamicContextVar.value.isDefined) errors.deprecated(m, location)

/** Record an exception as an error, and throw it.
  *
  * @param m exception message
  */
@throws(classOf[chisel3.ChiselException])

    buildImpl(f, dynamicContext)
  }
}

private def buildImpl[T <: BaseModule](
  f:              => T,
  dynamicContext: DynamicContext
): (ElaboratedCircuit, T) = {
  dynamicContextVar.withValue(Some(dynamicContext)) {
    // Must initialize the singleton in a Builder context or weird things can happen
    // in tiny designs/testcases that never access anything in chisel3.internal.
    ViewParent: Unit
    // Must initialize the singleton or OutOfMemoryErrors and StackOverflowErrors will instead report as
    // "java.lang.NoClassDefFoundError: Could not initialize class scala.util.control.NonFatal$".
    scala.util.control.NonFatal: Unit
    logger.info("Elaborating design...")
    // Register all layers.  This will ensure that the FIRRTL produce always includes these layers.
    chisel3.layers.defaultLayers.foreach(layer.addLayer)
    val mod =
      try {
        val m = f
        if (!inDefinition) { // This avoids definition name index skipping with D/I
          m._forceName(m.name, globalNamespace)
        }
        m
      } catch {
        case NonFatal(e) =>
          // Make sure to report any aggregated errors in case the Exception is due to a tainted return value
          // Note that errors.checkpoint may throw an Exception which will suppress e
          errors.checkpoint(logger)
          throw e
      }
    errors.checkpoint(logger)
    logger.info("Done elaborating.")

  if (Builder.readyForModuleConstr) {
    throwException(
      "Error: Called Module() twice without instantiating a Module." +
        sourceInfo.makeMessage(" See " + _)
    )
  }
  Builder.readyForModuleConstr = true
  Builder.elaborationTrace.pushModule()

  val savedPrefixStack = Builder.getModulePrefixStack

  val module = Builder.State.guard(Builder.State.default) {
    val module: T = bc

    if (Builder.whenDepth != 0) {
